import{_ as l,o as t,c as o,a2 as i}from"./chunks/framework.Crpw6aS5.js";const d=JSON.parse('{"title":"1956 年巴菲特合伙协议书","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1956年/翻译.md","filePath":"01_letters/1956年/翻译.md"}'),e={name:"01_letters/1956年/翻译.md"};function a(r,p,u,_,s,n){return t(),o("div",null,[...p[0]||(p[0]=[i('<h1 id="_1956-年巴菲特合伙协议书" tabindex="-1">1956 年巴菲特合伙协议书 <a class="header-anchor" href="#_1956-年巴菲特合伙协议书" aria-label="Permalink to &quot;1956 年巴菲特合伙协议书&quot;">​</a></h1><p>下述签署人特此证明，各方于今日成立有限合伙企业，并约定如下：</p><p>一、合伙企业名称：巴菲特联合有限公司。</p><p>二、业务性质：以合伙企业名义买卖股票、债券及其他有价证券、大宗商品及其他投资品种。</p><p>三、主要营业地点：内布拉斯加州道格拉斯县奥马哈市。</p><p>四、普通合伙人：沃伦·E·巴菲特（内布拉斯加州奥马哈市）。</p><p>有限合伙人：小查尔斯·E·彼得森，伊丽莎白·B·彼得森，多丽丝·B·伍德、杜鲁门·S·伍德、小丹尼尔·J·莫宁、威廉·H·汤普森、艾丽斯·R·巴菲特（均为内布拉斯加州奥马哈市），以下统称有限合伙人。</p><p>五、合伙期限：自1956年5月1日起至1976年4月30日止；除非根据合伙协议或内布拉斯加州法律提前终止。</p><p>六、各有限合伙人出资额如下：</p><ul><li>小查尔斯·E·彼得森：5,000美元</li><li>伊丽莎白·B·彼得森：25,000美元</li><li>多丽丝·B·伍德：5,000美元</li><li>杜鲁门·S·伍德：5,000美元</li><li>小丹尼尔·J·莫宁：5,000美元</li><li>威廉·H·汤普森：25,000美元</li><li>艾丽斯·R·巴菲特：35,000美元</li></ul><p>七、有限合伙人无需承担任何追加出资义务。</p><p>八、除合伙终止或有限合伙人退出合伙外，各方未就有限合伙人出资的返还约定具体时间。</p><p>九、各有限合伙人基于其出资可获得的利润份额或其他收益性报酬如下：</p><ol><li><p>每位有限合伙人有权就其上一年度12月31日的资本账户余额（以合伙企业当年联邦所得税申报表为准）按年利率4%收取利息，该利息计入合伙企业经营费用。</p></li><li><p>对于截至1956年12月31日的期间，替代上述年度利息，每位有限合伙人按其初始出资额的2%收取利息，该利息计入当期费用。</p></li><li><p>除此之外，各有限合伙人按以下比例分享合伙企业整体净利润（自成立至任意时点）：</p><ul><li>小查尔斯·E·彼得森：1/42</li><li>伊丽莎白·B·彼得森：5/42</li><li>多丽丝·B·伍德：1/42</li><li>杜鲁门·S·伍德：1/42</li><li>小丹尼尔·J·莫宁：1/42</li><li>威廉·H·汤普森：5/42</li><li>艾丽斯·R·巴菲特：7/42</li></ul></li></ol><p>十、有限合伙人无权指定受让人替代其成为出资方。</p><p>十一、合伙人无权接纳新的有限合伙人入伙。</p><p>十二、有限合伙人之间不存在优先顺序。</p><p>十三、若普通合伙人死亡、退休或精神失常，剩余合伙人无权继续经营合伙业务。</p><p>十四、有限合伙人无权要求或接受现金以外的财产作为出资返还。</p><p>签署日期：1956年5月1日</p><hr><h1 id="_1957年致合伙人信" tabindex="-1">1957年致合伙人信 <a class="header-anchor" href="#_1957年致合伙人信" aria-label="Permalink to &quot;1957年致合伙人信&quot;">​</a></h1><p>沃伦·E·巴菲特 内布拉斯加州奥马哈市安德伍德大道5202号</p><p>1957年股市概况</p><p>在去年的致合伙人信中，我说了以下观点：</p><p>我对整体市场水平的看法是，股价高于内在价值。这一观点主要针对蓝筹股。如果这一观点正确，则意味着所有股票价格都可能出现大幅下跌，无论是否被低估。无论如何，我认为五年后回头看，当前市场水平被认为&quot;便宜&quot;的可能性非常小。然而，即使是一场全面的熊市，也不应该大幅损害我们&quot;workout&quot;投资的市场价值。</p><p>如果市场回到被低估的状态，我们的资本可能会专门用于一般股票投资，届时或许还会使用一些借来的资金。相反，如果市场大幅上涨，我们的策略将是趁利润实现时减少一般股票投资，增加workout投资组合。</p><p>上述一切并非要表明市场分析是我首要关注的。我始终将主要注意力放在发现严重被低估的证券上。</p><p>过去一年，股票价格出现了温和下跌。我强调&quot;温和&quot;这个词，因为随意阅读报纸或与最近才接触股票的人交谈，会给人一种跌幅更大的印象。事实上，在我看来，股票价格的下跌远不及当前商业环境下企业盈利能力的下跌。这意味着公众对蓝筹股和整体经济前景仍然非常看好。我无意预测商业或股票市场；上述观点只是想消除股票已遭受严重下跌或整体市场处于低位的观念。基于长期投资价值，我仍然认为整体市场估值偏高。</p><p>1957年我们的活动</p><p>市场下跌为低估证券创造了更多机会，因此总的来说，我们投资组合中相对于workout的低估证券比去年更重。或许有必要解释一下&quot;workout&quot;这个术语。Workout是一种依赖于特定公司行为来获利的投资，而非像低估证券那样依赖于股价的一般性上涨。Workout通过以下方式产生：出售、并购、清算，要约收购等。在每种情况下，风险在于某些事情会打乱计划导致该行动被放弃，而不是经济前景恶化或股市整体下跌。截至1956年底，我们的一般股票投资与workout的比例约为70-30，现在约为85-15。</p><p>过去一年，我们持仓中有两个已经达到一定规模，有望参与公司决策。其中一个持仓占各合伙企业投资组合的10%至20%，另一个约占5%。两者都可能需要三到五年的时间才能见效，但目前看来具有获得高平均年回报率的潜力，同时风险最小。虽然不属于workout类别，但它们与股市整体走势的关联非常小。当然，如果市场大幅上涨，我预计我们投资组合的这一部分会落后于市场表现。</p><p>1957年业绩</p><p>1957年，我们于1956年组建的三个合伙企业的表现明显优于大盘。年初，道琼斯工业平均指数为499，年末为435，下跌64点。如果持有该指数，投资者将获得22点的股息，将整体亏损减少至42点，即全年亏损8.47%。这一亏损与投资大多数基金的结果大致相当，据我所知，没有投资股票的基金在当年取得正收益。</p><p>1956年成立的三个合伙企业在当年的收益分别约为年初净资产的6.2%、7.8%和25%。自然会产生一个问题：为什么最后一个合伙企业表现如此出色，尤其是前两个合伙企业的合伙人。这一业绩凸显了短期内运气的重要性，特别是资金到账的时机。第三个合伙企业在1956年最晚成立，当时市场处于较低水平，有几只证券特别具有吸引力。由于资金充足，我们对这些证券大量建仓。而较早成立的的两个合伙企业已经大量投资，因此只能少量建仓这些证券。</p><p>基本上，所有合伙企业都投资于相同的证券，比例也大致相同。然而，尤其是在初期阶段，资金在不同的市场时点和水平到位，因此业绩差异比未来年份可能更大。多年来，只要业绩每年比指数好10%我就非常满意，所以对于这三个合伙企业来说，1957年是成功的一年，可能好于平均水平。</p><p>1957年中期成立的两个合伙企业，年内剩余时间的业绩与指数大致相同，自1957年合伙企业成立以来指数下跌约12%。目前他们的投资组合正开始接近1956年合伙企业的水平，未来整个群体的业绩应该会更加可比。</p><p>业绩解读</p><p>我们在1957年表现好于平均水平，在某种程度上是因为这是大多数股票表现较差的一年。相对而言，我们的表现在熊市可能比在牛市更好，因此对上述结果的推论应该考虑到这是一个我们本应表现相对较好的年份。如果大盘出现大幅上涨，只要能跟上指数的涨幅我就很满意了。</p><p>我可以肯定地说，1957年底我们的投资组合比1956年底更具价值。这既是因为股价普遍较低，也是因为我们有更多时间来收购那些只能耐心才能获得的严重低估的证券。之前我提到我们最大的持仓占各合伙企业资产的10%至20%。我计划最终让它占所有合伙企业资产的20%，但不能急于求成。显然，在任何收购期间，我们最希望看到的是股价持平或下跌，而不是上涨。因此在任何时候，我们投资组合的相当比例可能处于&quot;冻结&quot;状态。这一策略虽然需要耐心，但应该能最大化长期利润。</p><p>我已经尽力涵盖我认为可能令人感兴趣的要点，并披露我们的投资理念，但不谈论个股。如果对运营的任何方面有疑问，欢迎来信交流。</p>',41)])])}const q=l(e,[["render",a]]);export{d as __pageData,q as default};
